import {host} from '@/api'
export default {
	props: {
		headPicUrl: {
			type: String,
			default: ''
		},
		avatarHeight: {
			type: Number,
			default: 52
		}
	},
	data() {
		return {
			host: host
		}
	},
	computed: {
		size() {
			let size = 'small'
			if (this.avatarHeight > 100) {
				size = 'big'
			}
			return size
		}
	}
}
